#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
#include <string.h>

#define FIFO_PATH "/tmp/kf_fifo_01"

int main(void) {
    mkfifo(FIFO_PATH, 0600);
    int fd = open(FIFO_PATH, O_RDWR);
    const char *msg = "hello fifo";
    write(fd, msg, strlen(msg));
    char buf[32];
    ssize_t n = read(fd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("Received: %s\n", buf);
    close(fd);
    unlink(FIFO_PATH);
    return 0;
}

