#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
#include <string.h>

// ★ Stage 0 — Exemple complet avec mkfifo (FIFO nommé)
// Différence avec pipe anonyme :
//   pipe(fd)   → temporaire, existe seulement tant que le processus vit
//   mkfifo()   → fichier spécial dans le filesystem, partageable entre processus

#define FIFO_PATH "/tmp/kf_fifo_01"

int main(void) {
    mkfifo(FIFO_PATH, 0600);            // ★ crée le fichier FIFO (mode 600)
    int fd = open(FIFO_PATH, O_RDWR);  // ★ O_RDWR : pas de blocage en mono-processus
    const char *msg = "hello fifo";
    write(fd, msg, strlen(msg));        // ★ écriture dans le FIFO
    char buf[32];
    ssize_t n = read(fd, buf, sizeof(buf) - 1); // ★ lecture
    buf[n] = '\0';
    printf("Received: %s\n", buf);
    close(fd);
    unlink(FIFO_PATH);                  // ★ supprime le fichier FIFO
    return 0;
}

